--
-- Name: archive_old_jobs(integer); Type: FUNCTION; Schema: ag_catalog; Owner: -
--

CREATE FUNCTION ag_catalog.archive_old_jobs(days_threshold integer DEFAULT 30) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    archived_count INTEGER;
BEGIN
    INSERT INTO kg_logs.job_events (job_id, timestamp, event_type, details)
    SELECT
        job_id,
        completed_at,
        'archived',
        jsonb_build_object(
            'status', status,
            'ontology', ontology,
            'result', result
        )
    FROM kg_api.ingestion_jobs
    WHERE completed_at < NOW() - (days_threshold || ' days')::INTERVAL
      AND status IN ('completed', 'failed');

    DELETE FROM kg_api.ingestion_jobs
    WHERE completed_at < NOW() - (days_threshold || ' days')::INTERVAL
      AND status IN ('completed', 'failed');

    GET DIAGNOSTICS archived_count = ROW_COUNT;
    RETURN archived_count;
END;
$$;


