--
-- Name: expire_old_recommendations(integer); Type: FUNCTION; Schema: ag_catalog; Owner: -
--

CREATE FUNCTION ag_catalog.expire_old_recommendations(days_threshold integer DEFAULT 7) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    expired_count INTEGER;
BEGIN
    UPDATE kg_api.pruning_recommendations
    SET status = 'expired'
    WHERE status = 'pending'
      AND created_at < NOW() - (days_threshold || ' days')::INTERVAL
      AND expires_at IS NULL;

    GET DIAGNOSTICS expired_count = ROW_COUNT;
    RETURN expired_count;
END;
$$;


