--
-- Name: are_source_embeddings_stale(text, text); Type: FUNCTION; Schema: kg_api; Owner: -
--

CREATE FUNCTION kg_api.are_source_embeddings_stale(p_source_id text, p_current_source_hash text) RETURNS boolean
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_stored_hash TEXT;
BEGIN
    -- Get stored hash from any embedding for this source
    SELECT source_hash
    INTO v_stored_hash
    FROM kg_api.source_embeddings
    WHERE source_id = p_source_id
    LIMIT 1;

    -- If no embeddings exist, they're not stale (they're missing)
    IF v_stored_hash IS NULL THEN
        RETURN FALSE;
    END IF;

    -- Compare hashes
    RETURN v_stored_hash != p_current_source_hash;
END;
$$;


--
-- Name: FUNCTION are_source_embeddings_stale(p_source_id text, p_current_source_hash text); Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON FUNCTION kg_api.are_source_embeddings_stale(p_source_id text, p_current_source_hash text) IS 'ADR-068: Check if source embeddings are stale (source text changed)';


--
-- Name: auto_validate_vocabulary_embedding(); Type: FUNCTION; Schema: kg_api; Owner: -
--

CREATE FUNCTION kg_api.auto_validate_vocabulary_embedding() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Only validate if embedding was set/changed
    IF NEW.embedding IS NOT NULL THEN
        -- Get expected dimensions from active embedding profile
        DECLARE
            v_expected_dimensions INTEGER;
        BEGIN
            SELECT text_dimensions INTO v_expected_dimensions
            FROM kg_api.embedding_profile
            WHERE active = TRUE
            LIMIT 1;

            -- Validate embedding structure
            IF kg_api.validate_embedding(NEW.embedding, v_expected_dimensions) THEN
                NEW.embedding_validation_status := 'valid';

                -- Calculate quality score (basic: non-zero vector magnitude)
                -- Full quality scoring implemented in Python EmbeddingWorker
                NEW.embedding_quality_score := 1.0;
            ELSE
                NEW.embedding_validation_status := 'invalid';
                NEW.embedding_quality_score := 0.0;
            END IF;
        END;
    END IF;

    RETURN NEW;
END;
$$;


