--
-- Name: complete_graph_epoch(bigint, text); Type: FUNCTION; Schema: kg_api; Owner: -
--

CREATE FUNCTION kg_api.complete_graph_epoch(p_event_id bigint, p_status text DEFAULT 'completed'::text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_status NOT IN ('completed', 'failed') THEN
        RAISE EXCEPTION 'complete_graph_epoch: status must be completed or failed, got %', p_status;
    END IF;

    UPDATE kg_api.graph_epochs
       SET status = p_status
     WHERE event_id = p_event_id;
END;
$$;


--
-- Name: FUNCTION complete_graph_epoch(p_event_id bigint, p_status text); Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON FUNCTION kg_api.complete_graph_epoch(p_event_id bigint, p_status text) IS 'ADR-207/#384: resolve an epoch event recorded by record_graph_epoch(). Call with completed when the mutation transaction commits, failed when it aborts/rolls back. Until called, the event is in_progress and holds the committed watermark below its event_id.';


