-- Name: delete_source_embeddings(text, text); Type: FUNCTION; Schema: kg_api; Owner: -
--

CREATE FUNCTION kg_api.delete_source_embeddings(p_source_id text, p_strategy text DEFAULT NULL::text) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_deleted_count INTEGER;
BEGIN
    IF p_strategy IS NULL THEN
        -- Delete all embeddings for source
        DELETE FROM kg_api.source_embeddings
        WHERE source_id = p_source_id;
    ELSE
        -- Delete embeddings for specific strategy
        DELETE FROM kg_api.source_embeddings
        WHERE source_id = p_source_id
          AND chunk_strategy = p_strategy;
    END IF;

    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    RETURN v_deleted_count;
END;
$$;


