--
-- Name: record_graph_epoch(text, text, jsonb); Type: FUNCTION; Schema: kg_api; Owner: -
--

CREATE FUNCTION kg_api.record_graph_epoch(p_kind text, p_actor text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_event_id BIGINT;
    v_counter  BIGINT;
BEGIN
    SELECT counter INTO v_counter
    FROM public.graph_metrics
    WHERE metric_name = 'graph_change_counter';

    INSERT INTO kg_api.graph_epochs (kind, actor, counter_after, metadata)
    VALUES (p_kind, p_actor, v_counter, p_metadata)
    RETURNING event_id INTO v_event_id;

    RETURN v_event_id;
END;
$$;


--
-- Name: FUNCTION record_graph_epoch(p_kind text, p_actor text, p_metadata jsonb); Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON FUNCTION kg_api.record_graph_epoch(p_kind text, p_actor text, p_metadata jsonb) IS 'ADR-203: Record a new graph-mutation event and return its event_id. Call at the start of an ingestion job (or other mutation transaction) so the returned id can tag nodes created during the unit of work.';


--
-- Name: set_platform_config(character varying, text, character varying); Type: FUNCTION; Schema: kg_api; Owner: -
--

CREATE FUNCTION kg_api.set_platform_config(p_key character varying, p_value text, p_updated_by character varying DEFAULT 'system'::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO kg_api.platform_config (key, value, updated_at, updated_by)
    VALUES (p_key, p_value, NOW(), p_updated_by)
    ON CONFLICT (key) DO UPDATE SET
        value = EXCLUDED.value,
        updated_at = NOW(),
        updated_by = EXCLUDED.updated_by;
END;
$$;


