--
-- Name: validate_embedding(jsonb, integer); Type: FUNCTION; Schema: kg_api; Owner: -
--

CREATE FUNCTION kg_api.validate_embedding(p_embedding jsonb, p_expected_dimensions integer DEFAULT 768) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_array_length INTEGER;
BEGIN
    -- Check if embedding is a JSON array
    IF jsonb_typeof(p_embedding) != 'array' THEN
        RETURN FALSE;
    END IF;

    -- Check dimensionality
    v_array_length := jsonb_array_length(p_embedding);
    IF v_array_length != p_expected_dimensions THEN
        RETURN FALSE;
    END IF;

    -- Basic validation passed
    RETURN TRUE;
END;
$$;


