-- Name: FUNCTION validate_embedding(p_embedding jsonb, p_expected_dimensions integer); Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON FUNCTION kg_api.validate_embedding(p_embedding jsonb, p_expected_dimensions integer) IS 'ADR-045: Validates embedding structure (JSON array of expected dimensions)';


--
-- Name: audit_role_assignment(); Type: FUNCTION; Schema: kg_auth; Owner: -
--

CREATE FUNCTION kg_auth.audit_role_assignment() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        INSERT INTO kg_logs.audit_trail (user_id, action, resource_type, resource_id, details, outcome)
        VALUES (
            NEW.assigned_by,
            'assign_role',
            'user_roles',
            NEW.user_id::TEXT,
            jsonb_build_object(
                'role_name', NEW.role_name,
                'scope_type', NEW.scope_type,
                'scope_id', NEW.scope_id,
                'expires_at', NEW.expires_at
            ),
            'success'
        );
    ELSIF TG_OP = 'DELETE' THEN
        INSERT INTO kg_logs.audit_trail (action, resource_type, resource_id, details, outcome)
        VALUES (
            'unassign_role',
            'user_roles',
            OLD.user_id::TEXT,
            jsonb_build_object(
                'role_name', OLD.role_name,
                'scope_type', OLD.scope_type,
                'scope_id', OLD.scope_id
            ),
            'success'
        );
    END IF;
    RETURN NULL;
END;
$$;


--
-- Name: get_user_groups(integer); Type: FUNCTION; Schema: kg_auth; Owner: -
--

CREATE FUNCTION kg_auth.get_user_groups(p_user_id integer) RETURNS TABLE(group_id integer, group_name character varying)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    -- Return explicit group memberships
    RETURN QUERY
    SELECT g.id, g.group_name
    FROM kg_auth.groups g
    JOIN kg_auth.user_groups ug ON g.id = ug.group_id
    WHERE ug.user_id = p_user_id

    UNION

    -- Always include public group for all authenticated users
    SELECT 1, 'public'::VARCHAR;
END;
$$;


--
-- Name: FUNCTION get_user_groups(p_user_id integer); Type: COMMENT; Schema: kg_auth; Owner: -
--

COMMENT ON FUNCTION kg_auth.get_user_groups(p_user_id integer) IS 'Get all groups for user including implicit public membership';


--
-- Name: get_user_roles(integer); Type: FUNCTION; Schema: kg_auth; Owner: -
--

CREATE FUNCTION kg_auth.get_user_roles(p_user_id integer) RETURNS TABLE(role_name character varying, scope_type character varying, scope_id character varying)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        ur.role_name,
        ur.scope_type,
        ur.scope_id
    FROM kg_auth.user_roles ur
    WHERE ur.user_id = p_user_id
      AND (ur.expires_at IS NULL OR ur.expires_at > NOW());
END;
$$;


