COMMENT ON FUNCTION kg_auth.get_user_roles(p_user_id integer) IS 'Get all active roles for a user';


--
-- Name: has_access(integer, character varying, character varying, character varying); Type: FUNCTION; Schema: kg_auth; Owner: -
--

CREATE FUNCTION kg_auth.has_access(p_user_id integer, p_resource_type character varying, p_resource_id character varying, p_permission character varying DEFAULT 'read'::character varying) RETURNS boolean
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_has_access BOOLEAN := FALSE;
BEGIN
    -- Check 1: Is user the owner? (requires owner_id on resource - checked by caller)
    -- This function doesn't know about ownership, caller should check first

    -- Check 2: Does user have a direct grant?
    SELECT EXISTS (
        SELECT 1 FROM kg_auth.resource_grants
        WHERE resource_type = p_resource_type
          AND resource_id = p_resource_id
          AND principal_type = 'user'
          AND principal_id = p_user_id
          AND permission IN (p_permission, 'admin')  -- admin implies all permissions
    ) INTO v_has_access;

    IF v_has_access THEN
        RETURN TRUE;
    END IF;

    -- Check 3: Is user in a group with a grant?
    SELECT EXISTS (
        SELECT 1 FROM kg_auth.user_groups ug
        JOIN kg_auth.resource_grants rg
            ON rg.principal_type = 'group' AND rg.principal_id = ug.group_id
        WHERE ug.user_id = p_user_id
          AND rg.resource_type = p_resource_type
          AND rg.resource_id = p_resource_id
          AND rg.permission IN (p_permission, 'admin')
    ) INTO v_has_access;

    IF v_has_access THEN
        RETURN TRUE;
    END IF;

    -- Check 4: Is 'public' group granted access? (all authenticated users)
    SELECT EXISTS (
        SELECT 1 FROM kg_auth.resource_grants
        WHERE resource_type = p_resource_type
          AND resource_id = p_resource_id
          AND principal_type = 'group'
          AND principal_id = 1  -- public group ID
          AND permission IN (p_permission, 'admin')
    ) INTO v_has_access;

    RETURN v_has_access;
END;
$$;


--
-- Name: FUNCTION has_access(p_user_id integer, p_resource_type character varying, p_resource_id character varying, p_permission character varying); Type: COMMENT; Schema: kg_auth; Owner: -
--

COMMENT ON FUNCTION kg_auth.has_access(p_user_id integer, p_resource_type character varying, p_resource_id character varying, p_permission character varying) IS 'Check if user has access to specific resource via grants (ADR-082)';


--
-- Name: has_permission(integer, character varying, character varying, character varying); Type: FUNCTION; Schema: kg_auth; Owner: -
--

CREATE FUNCTION kg_auth.has_permission(p_user_id integer, p_resource_type character varying, p_action character varying, p_resource_id character varying DEFAULT NULL::character varying) RETURNS boolean
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_has_permission BOOLEAN := FALSE;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM kg_auth.user_roles ur
        JOIN kg_auth.role_permissions rp ON ur.role_name = rp.role_name
        WHERE ur.user_id = p_user_id
          AND rp.resource_type = p_resource_type
          AND rp.action = p_action
          AND rp.scope_type = 'global'
          AND rp.granted = TRUE
          AND (ur.expires_at IS NULL OR ur.expires_at > NOW())
    ) INTO v_has_permission;

    RETURN v_has_permission;
END;
$$;


--
-- Name: FUNCTION has_permission(p_user_id integer, p_resource_type character varying, p_action character varying, p_resource_id character varying); Type: COMMENT; Schema: kg_auth; Owner: -
--

COMMENT ON FUNCTION kg_auth.has_permission(p_user_id integer, p_resource_type character varying, p_action character varying, p_resource_id character varying) IS 'Check if user has permission (simple global check - extend for scoped permissions)';


--
-- Name: get_counter_delta(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_counter_delta(p_metric_name character varying) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_delta BIGINT;
BEGIN
    SELECT (counter - last_measured_counter) INTO v_delta
    FROM graph_metrics
    WHERE metric_name = p_metric_name;

    RETURN COALESCE(v_delta, 0);
END;
$$;


--
-- Name: FUNCTION get_counter_delta(p_metric_name character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_counter_delta(p_metric_name character varying) IS 'Get delta between current counter and last measured counter (staleness)';


--
-- Name: get_graph_snapshot(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_graph_snapshot() RETURNS TABLE(concepts bigint, edges bigint, sources bigint, vocab_types bigint, total_objects bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY SELECT
        (SELECT COUNT(*) FROM knowledge_graph."Concept"),
        (SELECT COUNT(*) FROM knowledge_graph._ag_label_edge),
        (SELECT COUNT(*) FROM knowledge_graph."Source"),
        (SELECT COUNT(*) FROM knowledge_graph."VocabType"),
        (SELECT COUNT(*) FROM knowledge_graph."Concept") +
        (SELECT COUNT(*) FROM knowledge_graph._ag_label_edge) +
        (SELECT COUNT(*) FROM knowledge_graph."Source") +
        (SELECT COUNT(*) FROM knowledge_graph."VocabType") +
        (SELECT COUNT(*) FROM knowledge_graph."VocabCategory") +
        (SELECT COUNT(*) FROM knowledge_graph."Instance") +
        (SELECT COUNT(*) FROM knowledge_graph."DocumentMeta");
END;
$$;


--
-- Name: FUNCTION get_graph_snapshot(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_graph_snapshot() IS 'Returns current graph object counts. Use total_objects to compare against stored
projection artifact metadata for cache invalidation. Fast (~5ms).';


--
-- Name: increment_counter(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.increment_counter(p_metric_name character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE graph_metrics
    SET counter = counter + 1,
        updated_at = CURRENT_TIMESTAMP
    WHERE metric_name = p_metric_name;

    -- Create metric if it doesn't exist
    IF NOT FOUND THEN
        INSERT INTO graph_metrics (metric_name, counter, last_measured_counter, updated_at)
        VALUES (p_metric_name, 1, 0, CURRENT_TIMESTAMP);
    END IF;
END;
$$;


--
-- Name: FUNCTION increment_counter(p_metric_name character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.increment_counter(p_metric_name character varying) IS 'Increment any metric counter and update timestamp';


--
-- Name: mark_measurement_complete(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.mark_measurement_complete(p_metric_name character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE graph_metrics
    SET last_measured_counter = counter,
        last_measured_at = CURRENT_TIMESTAMP
    WHERE metric_name = p_metric_name;
END;
$$;


--
-- Name: FUNCTION mark_measurement_complete(p_metric_name character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.mark_measurement_complete(p_metric_name character varying) IS 'Mark epistemic status measurement complete - resets delta to 0';


--
-- Name: refresh_graph_metrics(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_graph_metrics() RETURNS TABLE(metric_name text, old_value bigint, new_value bigint, changed boolean)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_concept_count BIGINT;
    v_edge_count BIGINT;
    v_vocab_type_count BIGINT;
    v_vocab_category_count BIGINT;
    v_source_count BIGINT;
    v_instance_count BIGINT;
    v_document_count BIGINT;
    v_graph_change_counter BIGINT;
    v_old_value BIGINT;
BEGIN
    -- Get current counts (fast parallel-safe queries)
    SELECT COUNT(*) INTO v_concept_count FROM knowledge_graph."Concept";
    SELECT COUNT(*) INTO v_edge_count FROM knowledge_graph._ag_label_edge;
    SELECT COUNT(*) INTO v_vocab_type_count FROM knowledge_graph."VocabType";
    SELECT COUNT(*) INTO v_vocab_category_count FROM knowledge_graph."VocabCategory";
    SELECT COUNT(*) INTO v_source_count FROM knowledge_graph."Source";
    SELECT COUNT(*) INTO v_instance_count FROM knowledge_graph."Instance";
    SELECT COUNT(*) INTO v_document_count FROM knowledge_graph."DocumentMeta";

    -- Compute unified graph change counter (sum of all objects)
    v_graph_change_counter := v_concept_count + v_edge_count + v_vocab_type_count +
                              v_vocab_category_count + v_source_count + v_instance_count +
                              v_document_count;

    -- Update concept_count
    SELECT counter INTO v_old_value FROM public.graph_metrics WHERE public.graph_metrics.metric_name = 'concept_count';
    UPDATE public.graph_metrics SET counter = v_concept_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'concept_count';
    metric_name := 'concept_count'; old_value := v_old_value; new_value := v_concept_count;
    changed := (v_old_value IS DISTINCT FROM v_concept_count); RETURN NEXT;

    -- Update total_edges
    SELECT counter INTO v_old_value FROM public.graph_metrics WHERE public.graph_metrics.metric_name = 'total_edges';
    UPDATE public.graph_metrics SET counter = v_edge_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'total_edges';
    metric_name := 'total_edges'; old_value := v_old_value; new_value := v_edge_count;
    changed := (v_old_value IS DISTINCT FROM v_edge_count); RETURN NEXT;

    -- Update vocabulary_type_count
    SELECT counter INTO v_old_value FROM public.graph_metrics WHERE public.graph_metrics.metric_name = 'vocabulary_type_count';
    UPDATE public.graph_metrics SET counter = v_vocab_type_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'vocabulary_type_count';
    metric_name := 'vocabulary_type_count'; old_value := v_old_value; new_value := v_vocab_type_count;
    changed := (v_old_value IS DISTINCT FROM v_vocab_type_count); RETURN NEXT;

    -- Update source_count
    SELECT counter INTO v_old_value FROM public.graph_metrics WHERE public.graph_metrics.metric_name = 'source_count';
    UPDATE public.graph_metrics SET counter = v_source_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'source_count';
    metric_name := 'source_count'; old_value := v_old_value; new_value := v_source_count;
    changed := (v_old_value IS DISTINCT FROM v_source_count); RETURN NEXT;

    -- Update instance_count
    SELECT counter INTO v_old_value FROM public.graph_metrics WHERE public.graph_metrics.metric_name = 'instance_count';
    UPDATE public.graph_metrics SET counter = v_instance_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'instance_count';
    metric_name := 'instance_count'; old_value := v_old_value; new_value := v_instance_count;
    changed := (v_old_value IS DISTINCT FROM v_instance_count); RETURN NEXT;

    -- Update graph_change_counter (unified counter for cache invalidation)
    SELECT counter INTO v_old_value FROM public.graph_metrics WHERE public.graph_metrics.metric_name = 'graph_change_counter';
    UPDATE public.graph_metrics SET counter = v_graph_change_counter, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'graph_change_counter';
    metric_name := 'graph_change_counter'; old_value := v_old_value; new_value := v_graph_change_counter;
    changed := (v_old_value IS DISTINCT FROM v_graph_change_counter); RETURN NEXT;

    -- Also update the legacy creation counters to match current state
    -- (These were meant to be trigger-incremented but AGE bypasses triggers)
    UPDATE public.graph_metrics SET counter = v_concept_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'concept_creation_counter';

    UPDATE public.graph_metrics SET counter = v_edge_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'relationship_creation_counter';

    UPDATE public.graph_metrics SET counter = v_vocab_type_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'vocabulary_creation_counter';

    UPDATE public.graph_metrics SET counter = v_vocab_type_count + v_vocab_category_count, updated_at = CURRENT_TIMESTAMP
    WHERE public.graph_metrics.metric_name = 'vocabulary_change_counter';
END;
$$;


--
-- Name: FUNCTION refresh_graph_metrics(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.refresh_graph_metrics() IS 'Refreshes all graph metrics from current counts. Call after ingestion or periodically.
Returns table showing which metrics changed. Safe to call repeatedly (idempotent).
Used for ADR-079 projection cache invalidation.';


--
-- Name: reset_all_counters(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reset_all_counters() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE graph_metrics
    SET counter = 0,
        last_measured_counter = 0,
        last_measured_at = NULL,
        updated_at = CURRENT_TIMESTAMP;
END;
$$;


--
-- Name: FUNCTION reset_all_counters(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.reset_all_counters() IS 'Reset ALL counters to 0 (operator maintenance task - use with caution)';


