-- Name: reset_counter(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reset_counter(p_metric_name character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE graph_metrics
    SET counter = 0,
        last_measured_counter = 0,
        last_measured_at = NULL,
        updated_at = CURRENT_TIMESTAMP
    WHERE metric_name = p_metric_name;
END;
$$;


--
-- Name: FUNCTION reset_counter(p_metric_name character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.reset_counter(p_metric_name character varying) IS 'Reset counter to 0 (operator maintenance task)';


--
-- Name: update_graph_snapshot_totals(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_graph_snapshot_totals() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Just call the new comprehensive function
    PERFORM public.refresh_graph_metrics();
END;
$$;


--
-- Name: FUNCTION update_graph_snapshot_totals(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.update_graph_snapshot_totals() IS 'DEPRECATED: Use refresh_graph_metrics() instead. Kept for backwards compatibility.';


--
-- Name: update_snapshot_totals(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_snapshot_totals() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Update concept count
    UPDATE graph_metrics
    SET counter = (SELECT COUNT(*) FROM ag_catalog.ag_vertex WHERE label = 'Concept'),
        updated_at = CURRENT_TIMESTAMP
    WHERE metric_name = 'concept_count';

    -- Update vocabulary type count
    UPDATE graph_metrics
    SET counter = (SELECT COUNT(*) FROM ag_catalog.ag_vertex WHERE label = 'VocabType'),
        updated_at = CURRENT_TIMESTAMP
    WHERE metric_name = 'vocabulary_type_count';

    -- Note: total_edges, source_count, instance_count would require similar queries
    -- but are omitted here to avoid cross-namespace queries
END;
$$;


--
-- Name: FUNCTION update_snapshot_totals(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.update_snapshot_totals() IS 'Update snapshot total counters from current graph state';


