);


--
-- Name: TABLE graph_epochs; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON TABLE kg_api.graph_epochs IS 'ADR-203: Monotonic event log of graph mutations. Distinct from graph_change_counter (ADR-079) which is a composite cache-invalidation checksum.';


