-- Name: COLUMN graph_epochs.kind; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON COLUMN kg_api.graph_epochs.kind IS 'ingestion | reasoning | annealing | edit. Determines whether occurred_at is semantically meaningful for the rows attributable to this event.';


--
-- Name: COLUMN graph_epochs.status; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON COLUMN kg_api.graph_epochs.status IS 'ADR-207/#384: in_progress (set at record_graph_epoch) | completed | failed. Only in_progress blocks the committed watermark — both completed and failed count toward it (per-chunk commits mean a failed job may have mutated the graph). The completed/failed split is for analytics (drop zero-instance jobs from hot/stale signals), not for freshness.';


--
-- Name: graph_epochs_event_id_seq; Type: SEQUENCE; Schema: kg_api; Owner: -
--

CREATE SEQUENCE kg_api.graph_epochs_event_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;


--
-- Name: graph_epochs_event_id_seq; Type: SEQUENCE OWNED BY; Schema: kg_api; Owner: -
--

ALTER SEQUENCE kg_api.graph_epochs_event_id_seq OWNED BY kg_api.graph_epochs.event_id;


--
-- Name: hot_concepts; Type: MATERIALIZED VIEW; Schema: kg_api; Owner: -
--

CREATE MATERIALIZED VIEW kg_api.hot_concepts AS
 SELECT concept_id,
    access_count,
    queries_as_start
   FROM kg_api.concept_access_stats
  WHERE (access_count > 50)
  ORDER BY access_count DESC
 LIMIT 100
  WITH NO DATA;


--
-- Name: hot_edges; Type: MATERIALIZED VIEW; Schema: kg_api; Owner: -
--

CREATE MATERIALIZED VIEW kg_api.hot_edges AS
 SELECT from_concept_id,
    to_concept_id,
    relationship_type,
    traversal_count
   FROM kg_api.edge_usage_stats
  WHERE (traversal_count > 100)
  ORDER BY traversal_count DESC
 LIMIT 1000
  WITH NO DATA;


