--
-- Name: COLUMN source_embeddings.start_offset; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON COLUMN kg_api.source_embeddings.start_offset IS 'Character offset in Source.full_text where chunk starts (0-based)';


--
-- Name: COLUMN source_embeddings.end_offset; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON COLUMN kg_api.source_embeddings.end_offset IS 'Character offset in Source.full_text where chunk ends (exclusive)';


--
-- Name: COLUMN source_embeddings.chunk_text; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON COLUMN kg_api.source_embeddings.chunk_text IS 'Actual chunk content stored for verification (should match Source.full_text[start_offset:end_offset])';


--
-- Name: COLUMN source_embeddings.chunk_hash; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON COLUMN kg_api.source_embeddings.chunk_hash IS 'SHA256 hash of chunk_text - verifies chunk integrity';


