--
-- Name: v_builtin_types_missing_embeddings; Type: VIEW; Schema: kg_api; Owner: -
--

CREATE VIEW kg_api.v_builtin_types_missing_embeddings AS
 SELECT relationship_type,
    description,
    category,
    usage_count,
    added_at
   FROM kg_api.relationship_vocabulary
  WHERE ((is_builtin = true) AND ((embedding IS NULL) OR ((embedding_validation_status)::text = 'stale'::text)) AND (is_active = true))
  ORDER BY usage_count DESC, relationship_type;


--
-- Name: VIEW v_builtin_types_missing_embeddings; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON VIEW kg_api.v_builtin_types_missing_embeddings IS 'ADR-045: Builtin vocabulary types requiring embedding generation (cold start initialization)';


--
-- Name: v_sources_missing_embeddings; Type: VIEW; Schema: kg_api; Owner: -
--

CREATE VIEW kg_api.v_sources_missing_embeddings AS
 SELECT source_id,
    document,
    paragraph,
    length(full_text) AS text_length,
    created_at
   FROM ( SELECT cypher.source_id,
            cypher.document,
            cypher.paragraph,
            cypher.full_text,
            cypher.content_hash,
            cypher.created_at
           FROM ( SELECT (_.source_id)::text AS source_id,
                    (_.document)::text AS document,
                    (_.paragraph)::integer AS paragraph,
                    (_.full_text)::text AS full_text,
                    (_.content_hash)::text AS content_hash,
                    (_.created_at)::text AS created_at
                   FROM ( SELECT ag_catalog.agtype_access_operator(VARIADIC ARRAY[_age_default_alias_previous_cypher_clause.s, '"source_id"'::ag_catalog.agtype]) AS source_id,
                            ag_catalog.agtype_access_operator(VARIADIC ARRAY[_age_default_alias_previous_cypher_clause.s, '"document"'::ag_catalog.agtype]) AS document,
                            ag_catalog.agtype_access_operator(VARIADIC ARRAY[_age_default_alias_previous_cypher_clause.s, '"paragraph"'::ag_catalog.agtype]) AS paragraph,
                            ag_catalog.agtype_access_operator(VARIADIC ARRAY[_age_default_alias_previous_cypher_clause.s, '"full_text"'::ag_catalog.agtype]) AS full_text,
                            ag_catalog.agtype_access_operator(VARIADIC ARRAY[_age_default_alias_previous_cypher_clause.s, '"content_hash"'::ag_catalog.agtype]) AS content_hash,
                            ag_catalog.agtype_access_operator(VARIADIC ARRAY[_age_default_alias_previous_cypher_clause.s, '"created_at"'::ag_catalog.agtype]) AS created_at
                           FROM ( SELECT NULL::ag_catalog.agtype AS s
                                   FROM knowledge_graph._ag_label_vertex s_1
                                  WHERE ('true'::ag_catalog.agtype OPERATOR(ag_catalog.=) 'false'::ag_catalog.agtype)) _age_default_alias_previous_cypher_clause) _) cypher) s
  WHERE (content_hash IS NULL)
  ORDER BY created_at DESC;


--
-- Name: VIEW v_sources_missing_embeddings; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON VIEW kg_api.v_sources_missing_embeddings IS 'ADR-068: Source nodes that need embedding generation (content_hash is NULL)';


--
-- Name: v_stale_source_embeddings; Type: VIEW; Schema: kg_api; Owner: -
--

CREATE VIEW kg_api.v_stale_source_embeddings AS
 SELECT se.source_id,
    se.chunk_index,
    se.chunk_strategy,
    se.source_hash AS stored_hash,
    s.content_hash AS current_hash,
    se.created_at AS embedding_created_at,
    se.embedding_model
   FROM (kg_api.source_embeddings se
     JOIN ( SELECT cypher.source_id,
            cypher.content_hash
           FROM ( SELECT (_.source_id)::text AS source_id,
                    (_.content_hash)::text AS content_hash
                   FROM ( SELECT ag_catalog.agtype_access_operator(VARIADIC ARRAY[_age_default_alias_previous_cypher_clause.s, '"source_id"'::ag_catalog.agtype]) AS source_id,
                            ag_catalog.agtype_access_operator(VARIADIC ARRAY[_age_default_alias_previous_cypher_clause.s, '"content_hash"'::ag_catalog.agtype]) AS content_hash
                           FROM ( SELECT NULL::ag_catalog.agtype AS s
                                   FROM knowledge_graph._ag_label_vertex s_1
                                  WHERE ('true'::ag_catalog.agtype OPERATOR(ag_catalog.=) 'false'::ag_catalog.agtype)) _age_default_alias_previous_cypher_clause) _) cypher) s ON ((se.source_id = s.source_id)))
  WHERE (se.source_hash <> s.content_hash)
  ORDER BY se.created_at DESC;


--
-- Name: VIEW v_stale_source_embeddings; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON VIEW kg_api.v_stale_source_embeddings IS 'ADR-068: Embeddings that are stale (source text changed since embedding generation)';


--
-- Name: v_types_needing_embedding_regeneration; Type: VIEW; Schema: kg_api; Owner: -
--

CREATE VIEW kg_api.v_types_needing_embedding_regeneration AS
 SELECT relationship_type,
    description,
    category,
    is_builtin,
    usage_count,
    embedding_model,
    embedding_generated_at,
        CASE
            WHEN (embedding IS NULL) THEN 'missing'::text
            WHEN ((embedding_validation_status)::text = 'stale'::text) THEN 'stale'::text
            WHEN ((embedding_validation_status)::text = 'invalid'::text) THEN 'invalid'::text
            ELSE 'unknown'::text
        END AS regeneration_reason
   FROM kg_api.relationship_vocabulary
  WHERE ((is_active = true) AND ((embedding IS NULL) OR ((embedding_validation_status)::text = ANY ((ARRAY['stale'::character varying, 'invalid'::character varying, 'pending'::character varying])::text[]))))
  ORDER BY is_builtin DESC, usage_count DESC, relationship_type;


--
-- Name: VIEW v_types_needing_embedding_regeneration; Type: COMMENT; Schema: kg_api; Owner: -
--

COMMENT ON VIEW kg_api.v_types_needing_embedding_regeneration IS 'ADR-045: All vocabulary types requiring embedding (re)generation, prioritized by builtin status and usage';


