--
-- Name: graph_metrics; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.graph_metrics (
    metric_name character varying(255) NOT NULL,
    counter bigint DEFAULT 0 NOT NULL,
    last_measured_counter bigint DEFAULT 0 NOT NULL,
    last_measured_at timestamp without time zone,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    notes text
);


--
-- Name: TABLE graph_metrics; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.graph_metrics IS 'Change counters for triggering periodic epistemic status measurement';


--
-- Name: COLUMN graph_metrics.metric_name; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.graph_metrics.metric_name IS 'Unique metric identifier (e.g., vocabulary_change_counter, concept_count)';


--
-- Name: COLUMN graph_metrics.counter; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.graph_metrics.counter IS 'Increments on every change (create/delete/consolidate) - never decrements';


--
-- Name: COLUMN graph_metrics.last_measured_counter; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.graph_metrics.last_measured_counter IS 'Counter value when epistemic status was last measured';


--
-- Name: COLUMN graph_metrics.last_measured_at; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.graph_metrics.last_measured_at IS 'Timestamp when epistemic status was last measured';


--
-- Name: COLUMN graph_metrics.updated_at; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.graph_metrics.updated_at IS 'Timestamp of last counter increment';


--
-- Name: graph_metrics_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.graph_metrics_summary AS
 SELECT metric_name,
    counter,
    last_measured_counter,
    (counter - last_measured_counter) AS delta_since_last_measure,
    updated_at,
        CASE
            WHEN ((metric_name)::text ~~ '%_count'::text) THEN 'snapshot'::text
            WHEN ((metric_name)::text = 'graph_change_counter'::text) THEN 'snapshot'::text
            WHEN ((metric_name)::text = ANY ((ARRAY['document_ingestion_counter'::character varying, 'chunk_processing_counter'::character varying, 'extraction_job_counter'::character varying, 'grounding_calculation_counter'::character varying, 'epistemic_measurement_counter'::character varying, 'vocabulary_consolidation_counter'::character varying])::text[])) THEN 'activity'::text
            ELSE 'legacy_structure'::text
        END AS counter_type,
    notes
   FROM public.graph_metrics
  ORDER BY
        CASE
            WHEN ((metric_name)::text ~~ '%_count'::text) THEN 'snapshot'::text
            WHEN ((metric_name)::text = 'graph_change_counter'::text) THEN 'snapshot'::text
            WHEN ((metric_name)::text = ANY ((ARRAY['document_ingestion_counter'::character varying, 'chunk_processing_counter'::character varying, 'extraction_job_counter'::character varying, 'grounding_calculation_counter'::character varying, 'epistemic_measurement_counter'::character varying, 'vocabulary_consolidation_counter'::character varying])::text[])) THEN 'activity'::text
            ELSE 'legacy_structure'::text
        END, metric_name;


--
-- Name: VIEW graph_metrics_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.graph_metrics_summary IS 'Summary view of all graph metrics. snapshot counters are refreshed by refresh_graph_metrics().
activity counters are incremented by application code. legacy_structure counters are kept
in sync with snapshots (AGE bypasses PostgreSQL triggers).';


