INSERT INTO kg_api.annealing_options (key, value, description, updated_at) VALUES ('automation_level', 'autonomous', 'Automation level: autonomous (default, proposals auto-execute), hitl (human review)', '2026-07-02 03:56:43.696505+00') ON CONFLICT DO NOTHING;
INSERT INTO kg_api.annealing_options (key, value, description, updated_at) VALUES ('min_ontology_age_epochs', '3', 'Ontology must exist for at least this many epochs before annealing evaluates it. Prevents acting on ontologies still settling from recent ingestion (#402 Defect C).', '2026-07-02 03:56:44.504252+00') ON CONFLICT DO NOTHING;
INSERT INTO kg_api.annealing_options (key, value, description, updated_at) VALUES ('min_ontology_concept_count', '5', 'Ontology must hold at least this many concepts before annealing evaluates it. Below this floor, scores are dominated by per-concept noise rather than ontology structure (#402 Defect C).', '2026-07-02 03:56:44.504252+00') ON CONFLICT DO NOTHING;
INSERT INTO kg_api.annealing_options (key, value, description, updated_at) VALUES ('failure_cooldown_epochs', '5', 'After a failed execution, suppress new proposals against the same (anchor_concept_id, proposal_type, target) triple for this many epochs. Bezier-tunable via ADJUST_CONTROL (ADR-206 Phase 3).', '2026-07-02 03:56:44.600978+00') ON CONFLICT DO NOTHING;
INSERT INTO kg_api.annealing_options (key, value, description, updated_at) VALUES ('max_proposals_per_cycle', '10', 'Maximum number of proposals (any verb) emitted in a single annealing cycle. Throttles decision volume under high ecological pressure. Bezier-tunable via ADJUST_CONTROL (ADR-206 Phase 3).', '2026-07-02 03:56:44.600978+00') ON CONFLICT DO NOTHING;
INSERT INTO kg_api.annealing_options (key, value, description, updated_at) VALUES ('min_activity_for_cycle', '1', 'Minimum number of epoch increments since the last cycle before a new cycle is eligible. Raises the no-op floor when the graph is quiet. Bezier-tunable via ADJUST_CONTROL (ADR-206 Phase 3).', '2026-07-02 03:56:44.600978+00') ON CONFLICT DO NOTHING;


